define <5 x i8> @longerMask(<3 x i8> %x) {
  %shuf = shufflevector <3 x i8> %x, <3 x i8> <i8 undef, i8 1, i8 2>, <5 x i32> <i32 2, i32 1, i32 4, i32 3, i32 0>
  %ins = insertelement <5 x i8> %shuf, i8 42, i17 4
  ret <5 x i8> %ins
}

define <3 x float> @twoShufUses(<3 x float> %x) {
  %shuf = shufflevector <3 x float> %x, <3 x float> <float undef, float 1.000000e+00, float 2.000000e+00>, <3 x i32> <i32 0, i32 4, i32 5>
  %ins = insertelement <3 x float> %shuf, float 4.200000e+01, i2 1
  %add = fadd <3 x float> %shuf, %ins
  ret <3 x float> %add
}

define <4 x i16> @blend_elements_from_load(ptr align 8 %_0) {
  %load = load <3 x i16>, ptr %_0, align 8
  %rv = shufflevector <3 x i16> <i16 0, i16 undef, i16 undef>, <3 x i16> %load, <4 x i32> <i32 0, i32 1, i32 3, i32 5>
  ret <4 x i16> %rv
}

define <2 x float> @uitofp_shuf_narrow(<4 x i32> %x, <4 x i32> %y) {
  %nx = uitofp <4 x i32> %x to <4 x float>
  %ny = uitofp <4 x i32> %y to <4 x float>
  %r = shufflevector <4 x float> %nx, <4 x float> %ny, <2 x i32> <i32 3, i32 5>
  ret <2 x float> %r
}
